'use client'

import { ExternalLink, Loader2 } from 'lucide-react'

import { DatabaseOverview } from './database-overview'
import { ExplorerBreadcrumb } from './explorer-breadcrumb'
import { ExplorerEmptyState } from './explorer-empty-state'
import { useExplorerState } from './hooks/use-explorer-state'
import { DataTab } from './tabs/data-tab'
import { DdlTab } from './tabs/ddl-tab'
import { DependenciesTab } from './tabs/dependencies-tab'
import { IndexesTab } from './tabs/indexes-tab'
import { StructureTab } from './tabs/structure-tab'
import Link from 'next/link'
import { useEffect, useRef, useState } from 'react'
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs'
import { useHostId } from '@/lib/swr'
import { cn } from '@/lib/utils'

interface ExplorerContentProps {
  hostName?: string
}

// Track which tabs have been visited for this table to enable pre-loading
function useTabVisitTracker(tableKey: string | null) {
  const [visitedTabs, setVisitedTabs] = useState<Set<string>>(new Set(['data']))
  const prevTableKey = useRef<string | null>(null)

  useEffect(() => {
    if (tableKey !== prevTableKey.current) {
      // Reset visited tabs when table changes
      setVisitedTabs(new Set(['data']))
      prevTableKey.current = tableKey
    }
  }, [tableKey])

  const markVisited = (tab: string) => {
    setVisitedTabs((prev) => new Set([...prev, tab]))
  }

  return { visitedTabs, markVisited }
}

export function ExplorerContent({ hostName }: ExplorerContentProps) {
  const hostId = useHostId()
  const { database, table, tab, setTab } = useExplorerState()
  const [isTabSwitching, setIsTabSwitching] = useState(false)
  const tableKey = database && table ? `${database}.${table}` : null
  const { visitedTabs, markVisited } = useTabVisitTracker(tableKey)

  // Handle tab switching with instant visual feedback
  const handleTabChange = (value: string) => {
    if (value === tab) return

    setIsTabSwitching(true)
    markVisited(value)
    setTab(value as any)

    // Clear switching state after a brief moment
    requestAnimationFrame(() => {
      setIsTabSwitching(false)
    })
  }

  if (!database) {
    return <ExplorerEmptyState />
  }

  // Show database-level overview when database selected but no table
  if (!table) {
    return <DatabaseOverview database={database} hostId={hostId} />
  }

  const partInfoUrl = `/part-info?host=${hostId}&database=${encodeURIComponent(database)}&table=${encodeURIComponent(table)}`

  return (
    <div className="flex h-full flex-col gap-4 overflow-y-auto p-4">
      <ExplorerBreadcrumb hostName={hostName} />

      <Tabs id="explorer-tabs" value={tab} onValueChange={handleTabChange}>
        <TabsList>
          <TabsTrigger value="data" className="gap-2">
            Data
            {isTabSwitching && tab === 'data' && (
              <Loader2 className="size-3 animate-spin" />
            )}
          </TabsTrigger>
          <TabsTrigger value="structure" className="gap-2">
            Structure
            {isTabSwitching && tab === 'structure' && (
              <Loader2 className="size-3 animate-spin" />
            )}
          </TabsTrigger>
          <TabsTrigger value="ddl" className="gap-2">
            DDL
            {isTabSwitching && tab === 'ddl' && (
              <Loader2 className="size-3 animate-spin" />
            )}
          </TabsTrigger>
          <TabsTrigger value="indexes" className="gap-2">
            Indexes
            {isTabSwitching && tab === 'indexes' && (
              <Loader2 className="size-3 animate-spin" />
            )}
          </TabsTrigger>
          <TabsTrigger value="dependencies" className="gap-2">
            Dependencies
            {isTabSwitching && tab === 'dependencies' && (
              <Loader2 className="size-3 animate-spin" />
            )}
          </TabsTrigger>
          <Link
            href={partInfoUrl}
            className="inline-flex items-center justify-center gap-1.5 whitespace-nowrap rounded-md px-3 py-1 text-sm font-medium ring-offset-background transition-all focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 text-muted-foreground hover:text-foreground hover:bg-muted"
          >
            Parts
            <ExternalLink className="size-3" />
          </Link>
        </TabsList>

        {/* Data tab: always force-mounted to preserve pagination state */}
        <TabsContent
          value="data"
          className={cn('mt-4', tab !== 'data' && 'hidden flex-none')}
          forceMount
        >
          <DataTab />
        </TabsContent>

        {/* Structure tab: don't force-mount due to complex filter state */}
        <TabsContent value="structure" className="mt-4 flex-none">
          <StructureTab />
        </TabsContent>

        {/* DDL tab: force-mount to keep content cached */}
        <TabsContent
          value="ddl"
          className={cn('mt-4', tab !== 'ddl' && 'hidden flex-none')}
          forceMount
        >
          {visitedTabs.has('ddl') && <DdlTab />}
        </TabsContent>

        {/* Indexes tab: force-mount to keep content cached */}
        <TabsContent
          value="indexes"
          className={cn('mt-4', tab !== 'indexes' && 'hidden flex-none')}
          forceMount
        >
          {visitedTabs.has('indexes') && <IndexesTab />}
        </TabsContent>

        {/* Dependencies tab: force-mount to keep content cached */}
        <TabsContent
          value="dependencies"
          className={cn('mt-4', tab !== 'dependencies' && 'hidden flex-none')}
          forceMount
        >
          {visitedTabs.has('dependencies') && <DependenciesTab />}
        </TabsContent>
      </Tabs>
    </div>
  )
}

'use client'

import { usePathname, useRouter, useSearchParams } from 'next/navigation'
import { useCallback, useMemo } from 'react'

export type ExplorerTab =
  | 'data'
  | 'structure'
  | 'ddl'
  | 'indexes'
  | 'dependencies'

export interface ExplorerState {
  hostId: number
  database: string | null
  table: string | null
  engine: string | null
  tab: ExplorerTab
}

export function useExplorerState(): ExplorerState & {
  setDatabase: (database: string | null) => void
  setTable: (table: string | null, engine?: string | null) => void
  setDatabaseAndTable: (
    database: string,
    table: string,
    engine?: string
  ) => void
  setTab: (tab: ExplorerTab) => void
} {
  const searchParams = useSearchParams()
  const router = useRouter()
  const pathname = usePathname()

  const state = useMemo<ExplorerState>(() => {
    const hostParam = searchParams.get('host')
    const hostId = hostParam !== null ? Number(hostParam) : 0

    return {
      hostId: Number.isNaN(hostId) ? 0 : hostId,
      database: searchParams.get('database'),
      table: searchParams.get('table'),
      engine: searchParams.get('engine'),
      tab: (searchParams.get('tab') as ExplorerTab) || 'data',
    }
  }, [searchParams])

  const updateParams = useCallback(
    (updates: Partial<Omit<ExplorerState, 'hostId'>>) => {
      const params = new URLSearchParams(searchParams.toString())

      if (updates.database !== undefined) {
        if (updates.database === null) {
          params.delete('database')
          params.delete('table') // Clear table when database is cleared
          params.delete('engine')
        } else {
          params.set('database', updates.database)
        }
      }

      if (updates.table !== undefined) {
        if (updates.table === null) {
          params.delete('table')
          params.delete('engine')
        } else {
          params.set('table', updates.table)
        }
      }

      if (updates.engine !== undefined) {
        if (updates.engine === null) {
          params.delete('engine')
        } else {
          params.set('engine', updates.engine)
        }
      }

      if (updates.tab !== undefined) {
        params.set('tab', updates.tab)
      }

      router.push(`${pathname}?${params.toString()}`)
    },
    [searchParams, pathname, router]
  )

  const setDatabase = useCallback(
    (database: string | null) => {
      updateParams({ database, table: null }) // Clear table when changing database
    },
    [updateParams]
  )

  const setTable = useCallback(
    (table: string | null, engine?: string | null) => {
      updateParams({ table, engine: engine ?? null })
    },
    [updateParams]
  )

  const setDatabaseAndTable = useCallback(
    (database: string, table: string, engine?: string) => {
      updateParams({ database, table, engine: engine ?? null, tab: 'data' })
    },
    [updateParams]
  )

  const setTab = useCallback(
    (tab: ExplorerTab) => {
      updateParams({ tab })
    },
    [updateParams]
  )

  return {
    ...state,
    setDatabase,
    setTable,
    setDatabaseAndTable,
    setTab,
  }
}

/**
 * Generic data endpoint for executing ClickHouse queries
 * POST /api/v1/data, GET /api/v1/data
 *
 * Accepts a query and parameters, returns data with metadata.
 * Includes caching headers for performance optimization.
 *
 * SECURITY: This endpoint validates that queries being executed are either:
 * 1. Pre-defined in the chart/table registries (recommended)
 * 2. Stored in the dashboard tables (for custom dashboards)
 * This prevents clients from sending arbitrary SQL queries.
 */

import type { DataFormat } from '@clickhouse/client'

import type { ApiRequest } from '@/lib/api/types'
import type { FetchDataError } from '@/lib/clickhouse'

import { validateDashboardQuery } from './validators/dashboard-query-validator'
import {
  createErrorResponse as createApiErrorResponse,
  createValidationError,
  withApiHandler,
} from '@/lib/api/error-handler'
import { createSuccessResponse } from '@/lib/api/shared/response-builder'
import { mapErrorTypeToStatusCode } from '@/lib/api/shared/status-code-mapper'
import {
  getAndValidateHostId,
  validateDataRequest,
  validateSearchParams,
  validateSqlQuery,
} from '@/lib/api/shared/validators'
import { ApiErrorType } from '@/lib/api/types'
import { fetchData } from '@/lib/clickhouse'
import { debug, error } from '@/lib/logger'

// This route is dynamic and should not be statically exported
export const dynamic = 'force-dynamic'

const ROUTE_CONTEXT = { route: '/api/v1/data' }

/**
 * Handle GET requests for data fetching
 * Accepts query and parameters via URL query string
 *
 * @example
 * GET /api/v1/data?hostId=0&sql=SELECT%20count()%20FROM%20system.tables&format=JSONEachRow
 */
export const GET = withApiHandler(async (request: Request) => {
  const url = new URL(request.url)
  const searchParams = url.searchParams

  // Parse query parameters from URL
  const query =
    searchParams.get('sql') || searchParams.get('query') || undefined
  const format = searchParams.get('format') as DataFormat | null
  const timezone = searchParams.get('timezone') || undefined

  // Validate required parameters
  const validationError = validateSearchParams(searchParams, ['hostId'])
  if (validationError) {
    return createValidationError(validationError.message, {
      ...ROUTE_CONTEXT,
      method: 'GET',
    })
  }

  if (!query) {
    return createValidationError('Missing required parameter: sql or query', {
      ...ROUTE_CONTEXT,
      method: 'GET',
    })
  }

  // SECURITY: Validate SQL query to prevent injection attacks
  try {
    validateSqlQuery(query)
  } catch (validationError) {
    error('[GET /api/v1/data] Security: SQL validation failed', {
      queryPreview: query.substring(0, 100),
      error:
        validationError instanceof Error
          ? validationError.message
          : 'Unknown error',
    })
    return createValidationError(
      validationError instanceof Error
        ? validationError.message
        : 'SQL validation failed',
      { ...ROUTE_CONTEXT, method: 'GET' }
    )
  }

  // Get and validate hostId from search params
  const hostIdResult = getAndValidateHostId(searchParams)
  if (typeof hostIdResult !== 'number') {
    return createValidationError(hostIdResult.message, {
      ...ROUTE_CONTEXT,
      method: 'GET',
    })
  }
  const hostId = hostIdResult

  debug('[GET /api/v1/data]', {
    hostId,
    format: format || 'JSONEachRow',
    timezone,
  })

  // Execute the query
  const result = await fetchData({
    query,
    format: (format || 'JSONEachRow') as DataFormat,
    hostId,
    // Pass timezone to ClickHouse for session-level time conversion
    clickhouse_settings: timezone ? { session_timezone: timezone } : undefined,
  })

  // Handle errors
  if (result.error) {
    error('[GET /api/v1/data] Query error:', result.error)
    return handleQueryError(result.error, hostId, 'GET')
  }

  // Create successful response with timezone in metadata
  return createSuccessResponse(result.data, { ...result.metadata, timezone })
}, ROUTE_CONTEXT)

/**
 * Handle POST requests for data fetching
 * Accepts query and parameters in the request body
 *
 * SECURITY: When queryConfig is not provided, validates that the query
 * exists in the dashboard tables to prevent arbitrary SQL execution.
 *
 * @example
 * POST /api/v1/data
 * {
 *   "query": "SELECT count() FROM system.tables",
 *   "hostId": 0,
 *   "format": "JSONEachRow"
 * }
 */
export const POST = withApiHandler(async (request: Request) => {
  // Parse request body
  const body = (await request.json()) as Partial<ApiRequest>

  // Validate required fields using shared validator
  const validationError = validateDataRequest(body)
  if (validationError) {
    return createApiErrorResponse(validationError, 400, {
      ...ROUTE_CONTEXT,
      method: 'POST',
    })
  }

  const typedBody = body as ApiRequest
  const {
    query,
    queryParams,
    hostId,
    format = 'JSONEachRow',
    queryConfig,
    timezone,
  } = typedBody

  debug('[POST /api/v1/data]', {
    hostId,
    format,
    queryConfig: queryConfig?.name,
    timezone,
  })

  // SECURITY: If no queryConfig provided, validate the query exists in dashboard tables
  // This prevents arbitrary SQL execution from clients
  if (!queryConfig) {
    const validationResult = await validateDashboardQuery(query, Number(hostId))
    if (!validationResult.valid) {
      error(
        '[POST /api/v1/data] Security: Query not found in dashboard tables',
        {
          queryPreview: query.substring(0, 100),
        }
      )
      return createApiErrorResponse(
        {
          type: ApiErrorType.PermissionError,
          message: validationResult.error?.message || 'Query validation failed',
        },
        403,
        { ...ROUTE_CONTEXT, method: 'POST', hostId }
      )
    }
  }

  // Convert format string to DataFormat if needed
  const dataFormat = (format || 'JSONEachRow') as DataFormat

  // Execute the query
  const result = await fetchData({
    query,
    query_params: queryParams,
    format: dataFormat,
    hostId,
    queryConfig,
    // Pass timezone to ClickHouse for session-level time conversion
    clickhouse_settings: timezone ? { session_timezone: timezone } : undefined,
  })

  // Handle errors
  if (result.error) {
    error('[POST /api/v1/data] Query error:', result.error)
    return handleQueryError(result.error, hostId, 'POST')
  }

  // Create successful response with timezone in metadata
  return createSuccessResponse(result.data, { ...result.metadata, timezone })
}, ROUTE_CONTEXT)

/**
 * Handle query execution errors with proper status code mapping
 *
 * @param queryError - The FetchDataError returned from fetchData
 * @param hostId - The host identifier for logging
 * @param method - HTTP method for logging
 * @returns Error response with appropriate status code
 */
function handleQueryError(
  queryError: FetchDataError,
  hostId: string | number,
  method: string
): Response {
  // Map FetchDataErrorType to ApiErrorType
  const errorTypeMap: Record<FetchDataError['type'], ApiErrorType> = {
    table_not_found: ApiErrorType.TableNotFound,
    validation_error: ApiErrorType.ValidationError,
    query_error: ApiErrorType.QueryError,
    network_error: ApiErrorType.NetworkError,
    permission_error: ApiErrorType.PermissionError,
  }

  const apiErrorType = errorTypeMap[queryError.type] ?? ApiErrorType.QueryError

  return createApiErrorResponse(
    {
      type: apiErrorType,
      message: queryError.message,
      details: queryError.details as Record<
        string,
        string | number | boolean | undefined
      >,
    },
    mapErrorTypeToStatusCode(apiErrorType),
    { ...ROUTE_CONTEXT, method, hostId }
  )
}

/**
 * Explorer preview endpoint
 * GET /api/v1/explorer/preview?hostId=0&database=default&table=users&limit=100
 *
 * Returns preview data (SELECT *) from a table with pagination
 */

import type { NextRequest } from 'next/server'
import type { ApiResponse } from '@/lib/api/types'

import {
  createErrorResponse as createApiErrorResponse,
  getHostIdFromParams,
  type RouteContext,
} from '@/lib/api/error-handler'
import { ApiErrorType } from '@/lib/api/types'
import { fetchData } from '@/lib/clickhouse'
import { debug, error } from '@/lib/logger'

export const dynamic = 'force-dynamic'

const ROUTE_CONTEXT_BASE = { route: '/api/v1/explorer/preview' }

// Validation regex for identifiers (database and table names)
const VALID_IDENTIFIER = /^[a-zA-Z_][a-zA-Z0-9_]*$/

/**
 * Handle GET requests for table preview
 */
export async function GET(request: NextRequest): Promise<Response> {
  const { searchParams } = new URL(request.url)
  const routeContext: RouteContext = {
    ...ROUTE_CONTEXT_BASE,
    method: 'GET',
  }

  // Extract and validate hostId
  const hostId = getHostIdFromParams(searchParams, routeContext)

  // Extract database and table names
  const database = searchParams.get('database')
  const table = searchParams.get('table')
  const limit = searchParams.get('limit') || '100'

  debug(`[GET /api/v1/explorer/preview]`, { hostId, database, table, limit })

  // Validate database parameter
  if (!database || !VALID_IDENTIFIER.test(database)) {
    return createApiErrorResponse(
      {
        type: ApiErrorType.ValidationError,
        message: 'Invalid database identifier',
        details: {
          database: database || 'missing',
        },
      },
      400,
      routeContext
    )
  }

  // Validate table parameter
  if (!table || !VALID_IDENTIFIER.test(table)) {
    return createApiErrorResponse(
      {
        type: ApiErrorType.ValidationError,
        message: 'Invalid table identifier',
        details: {
          table: table || 'missing',
        },
      },
      400,
      routeContext
    )
  }

  // Validate limit parameter (must be numeric and reasonable)
  const parsedLimit = parseInt(limit, 10)
  if (Number.isNaN(parsedLimit) || parsedLimit < 1 || parsedLimit > 10000) {
    return createApiErrorResponse(
      {
        type: ApiErrorType.ValidationError,
        message: 'Invalid limit parameter (must be between 1 and 10000)',
        details: {
          limit,
        },
      },
      400,
      routeContext
    )
  }

  // Build safe query using backticks for identifiers
  const query = `SELECT * FROM \`${database}\`.\`${table}\` LIMIT ${parsedLimit}`

  debug(`[GET /api/v1/explorer/preview] Executing query:`, { query })

  // Execute the query
  const result = await fetchData({
    query,
    hostId,
    format: 'JSONEachRow',
  })

  // Check if there was an error
  if (result.error) {
    error(`[GET /api/v1/explorer/preview] Query error:`, result.error)
    return createApiErrorResponse(
      {
        type: result.error.type as ApiErrorType,
        message: result.error.message,
        details: result.error.details as Record<
          string,
          string | number | boolean | undefined
        >,
      },
      mapErrorTypeToStatusCode(result.error.type as ApiErrorType),
      { ...routeContext, hostId }
    )
  }

  // Create successful response
  return createSuccessResponse(result.data, result.metadata)
}

/**
 * Map error type to HTTP status code
 */
function mapErrorTypeToStatusCode(errorType: ApiErrorType): number {
  const statusMap: Record<ApiErrorType, number> = {
    [ApiErrorType.ValidationError]: 400,
    [ApiErrorType.PermissionError]: 403,
    [ApiErrorType.TableNotFound]: 404,
    [ApiErrorType.NetworkError]: 503,
    [ApiErrorType.QueryError]: 500,
  }

  return statusMap[errorType] || 500
}

/**
 * Create a success response
 */
function createSuccessResponse<T>(
  data: T,
  metadata: Record<string, string | number>
): Response {
  const response: ApiResponse<T> = {
    success: true,
    data,
    metadata: {
      queryId: String(metadata.queryId || ''),
      duration: Number(metadata.duration || 0),
      rows: Number(metadata.rows || 0),
      host: String(metadata.host || ''),
    },
  }

  return Response.json(response, {
    status: 200,
    headers: {
      'Content-Type': 'application/json',
      'Cache-Control': 'private, max-age=0',
    },
  })
}

'use client'

import { AlertCircle, Loader2, RefreshCw, ShieldAlert } from 'lucide-react'
import useSWR from 'swr'
import {
  createColumnHelper,
  flexRender,
  getCoreRowModel,
  useReactTable,
} from '@tanstack/react-table'

import type { ApiError, ApiResponse } from '@/lib/api/types'

import { useExplorerState } from '../hooks/use-explorer-state'
import { memo, useCallback, useMemo, useState } from 'react'
import { TableSkeleton } from '@/components/skeletons'
import { Alert, AlertDescription, AlertTitle } from '@/components/ui/alert'
import { Button } from '@/components/ui/button'
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select'
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from '@/components/ui/table'
import { useHostId } from '@/lib/swr/use-host'
import { cn } from '@/lib/utils'

const MAX_CELL_LENGTH = 100

/**
 * Expandable cell component for long text content
 * Shows truncated text inline with click-to-expand functionality
 */
const ExpandableCell = memo(function ExpandableCell({
  value,
}: {
  value: unknown
}) {
  const [expanded, setExpanded] = useState(false)
  const stringValue = String(value ?? '')
  const isLong = stringValue.length > MAX_CELL_LENGTH

  const toggleExpand = useCallback(() => {
    setExpanded((prev) => !prev)
  }, [])

  const handleKeyDown = useCallback(
    (e: React.KeyboardEvent) => {
      if (e.key === 'Enter' || e.key === ' ') {
        e.preventDefault()
        toggleExpand()
      }
    },
    [toggleExpand]
  )

  if (!isLong) {
    return <span className="block truncate">{stringValue}</span>
  }

  return (
    <span
      role="button"
      tabIndex={0}
      onClick={toggleExpand}
      onKeyDown={handleKeyDown}
      className={cn(
        'block cursor-pointer transition-colors',
        expanded ? 'whitespace-pre-wrap break-words' : 'truncate',
        !expanded && 'hover:text-primary'
      )}
      title={expanded ? 'Click to collapse' : 'Click to expand'}
      aria-expanded={expanded}
    >
      {expanded ? stringValue : `${stringValue.slice(0, MAX_CELL_LENGTH)}…`}
    </span>
  )
})

/** Custom error class to carry API error details */
class DataTabError extends Error {
  type: string
  details?: Record<string, unknown>

  constructor(apiError: ApiError) {
    super(apiError.message)
    this.name = 'DataTabError'
    this.type = apiError.type
    this.details = apiError.details as Record<string, unknown> | undefined
  }
}

const PAGE_SIZE_OPTIONS = [100, 500, 1000] as const

const fetcher = async (
  url: string
): Promise<ApiResponse<Record<string, unknown>[]>> => {
  const res = await fetch(url)
  const json = (await res.json()) as ApiResponse<Record<string, unknown>[]>

  // Check for API-level errors
  if (!json.success && json.error) {
    throw new DataTabError(json.error)
  }

  return json
}

type RowData = Record<string, unknown>
const columnHelper = createColumnHelper<RowData>()

export function DataTab() {
  const hostId = useHostId()
  const { database, table: tableName } = useExplorerState()
  const [limit, setLimit] = useState<number>(100)
  const [offset, setOffset] = useState<number>(0)

  const {
    data: response,
    error,
    isLoading,
    isValidating,
    mutate,
  } = useSWR<ApiResponse<RowData[]>>(
    database && tableName
      ? `/api/v1/explorer/preview?hostId=${hostId}&database=${encodeURIComponent(database)}&table=${encodeURIComponent(tableName)}&limit=${limit}&offset=${offset}`
      : null,
    fetcher,
    {
      keepPreviousData: true,
    }
  )

  const rows = response?.data || []

  // Generate columns dynamically from data
  const columns = useMemo(() => {
    if (rows.length === 0) return []
    return Object.keys(rows[0]).map((key) =>
      columnHelper.accessor(key, {
        header: key,
        cell: (info) => <ExpandableCell value={info.getValue()} />,
        size: 200,
        minSize: 80,
        maxSize: 500,
      })
    )
  }, [rows])

  const table = useReactTable({
    data: rows,
    columns,
    getCoreRowModel: getCoreRowModel(),
    columnResizeMode: 'onChange',
    defaultColumn: {
      size: 200,
      minSize: 80,
      maxSize: 500,
    },
  })

  if (!database || !tableName) {
    return null
  }

  if (isLoading && !response) {
    return <TableSkeleton />
  }

  if (error) {
    const isPermissionError =
      error instanceof DataTabError && error.type === 'permission_error'
    const Icon = isPermissionError ? ShieldAlert : AlertCircle

    return (
      <Alert
        variant="destructive"
        className={cn(
          isPermissionError && 'border-amber-500/50 bg-amber-500/10'
        )}
      >
        <Icon className="size-4" />
        <AlertTitle>
          {isPermissionError ? 'Permission Denied' : 'Failed to load data'}
        </AlertTitle>
        <AlertDescription className="mt-2 space-y-2">
          <p className="text-sm">
            {isPermissionError
              ? `You don't have permission to access this table. This may be a linked external database (PostgreSQL, MySQL, etc.) with restricted access.`
              : error.message}
          </p>
          {!isPermissionError && (
            <Button
              variant="outline"
              size="sm"
              onClick={() => mutate()}
              className="mt-2"
            >
              <RefreshCw className="mr-1.5 size-3" />
              Retry
            </Button>
          )}
        </AlertDescription>
      </Alert>
    )
  }

  if (rows.length === 0 && !isValidating) {
    return (
      <div className="p-4 text-sm text-muted-foreground">
        No data available for {database}.{tableName}
      </div>
    )
  }

  const currentPage = Math.floor(offset / limit) + 1
  const hasNextPage = rows.length === limit
  const isPaginating = isValidating && !!response

  return (
    <div className="flex flex-col gap-4">
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-2">
          <span className="text-sm text-muted-foreground">Rows per page:</span>
          <Select
            value={String(limit)}
            onValueChange={(v) => {
              setLimit(Number(v))
              setOffset(0)
            }}
            disabled={isPaginating}
          >
            <SelectTrigger className="w-24">
              <SelectValue />
            </SelectTrigger>
            <SelectContent>
              {PAGE_SIZE_OPTIONS.map((size) => (
                <SelectItem key={size} value={String(size)}>
                  {size}
                </SelectItem>
              ))}
            </SelectContent>
          </Select>
        </div>

        <div className="flex items-center gap-2">
          {isPaginating && (
            <Loader2 className="size-4 animate-spin text-muted-foreground" />
          )}
          <span className="text-sm text-muted-foreground">
            Page {currentPage}
          </span>
          <Button
            variant="outline"
            size="sm"
            disabled={offset === 0 || isPaginating}
            onClick={() => setOffset(Math.max(0, offset - limit))}
          >
            Previous
          </Button>
          <Button
            variant="outline"
            size="sm"
            disabled={!hasNextPage || isPaginating}
            onClick={() => setOffset(offset + limit)}
          >
            Next
          </Button>
        </div>
      </div>

      <div
        className={cn(
          'overflow-x-auto rounded-md border transition-opacity',
          isPaginating && 'opacity-60'
        )}
      >
        <Table
          style={{
            minWidth: table.getCenterTotalSize(),
            width: '100%',
          }}
        >
          <TableHeader className="bg-muted/50">
            {table.getHeaderGroups().map((headerGroup) => (
              <TableRow key={headerGroup.id}>
                {headerGroup.headers.map((header) => (
                  <TableHead
                    key={header.id}
                    className="relative select-none"
                    style={{
                      minWidth: header.getSize(),
                    }}
                  >
                    {header.isPlaceholder
                      ? null
                      : flexRender(
                          header.column.columnDef.header,
                          header.getContext()
                        )}
                    {/* Column resize handle */}
                    <div
                      role="presentation"
                      onDoubleClick={() => header.column.resetSize()}
                      onMouseDown={header.getResizeHandler()}
                      onTouchStart={header.getResizeHandler()}
                      className={cn(
                        'absolute right-0 top-0 h-full w-1 cursor-col-resize select-none touch-none',
                        'bg-transparent hover:bg-primary/50',
                        header.column.getIsResizing() && 'bg-primary'
                      )}
                    />
                  </TableHead>
                ))}
              </TableRow>
            ))}
          </TableHeader>
          <TableBody>
            {table.getRowModel().rows.map((row) => (
              <TableRow key={row.id} className="hover:bg-muted/50">
                {row.getVisibleCells().map((cell) => (
                  <TableCell
                    key={cell.id}
                    style={{
                      minWidth: cell.column.getSize(),
                    }}
                  >
                    {flexRender(cell.column.columnDef.cell, cell.getContext())}
                  </TableCell>
                ))}
              </TableRow>
            ))}
          </TableBody>
        </Table>
      </div>
    </div>
  )
}

/**
 * Explain Query endpoint
 * GET /api/v1/explain?hostId=0&query=SELECT...
 *
 * Executes EXPLAIN on the provided query and returns the execution plan.
 */

import type { NextRequest } from 'next/server'

import {
  createErrorResponse,
  createValidationError,
} from '@/lib/api/error-handler'
import { createCachedResponse } from '@/lib/api/shared/response-builder'
import { mapErrorTypeToStatusCode } from '@/lib/api/shared/status-code-mapper'
import { getAndValidateHostId } from '@/lib/api/shared/validators'
import { validateSqlQuery } from '@/lib/api/shared/validators/sql'
import { ApiErrorType } from '@/lib/api/types'
import { fetchData } from '@/lib/clickhouse'
import { debug, error as logError } from '@/lib/logger'

export const dynamic = 'force-dynamic'

const ROUTE_CONTEXT = { route: '/api/v1/explain', method: 'GET' }

/**
 * Handle GET requests for EXPLAIN queries
 * Accepts query via URL query string
 *
 * @example
 * GET /api/v1/explain?hostId=0&query=SELECT%20count()%20FROM%20system.tables
 */
export async function GET(request: NextRequest): Promise<Response> {
  const { searchParams } = new URL(request.url)

  // Validate required parameters
  const validationError = validateSearchParams(searchParams)
  if (validationError) {
    return createValidationError(validationError.message, ROUTE_CONTEXT)
  }

  // Get and validate hostId
  const hostIdResult = getAndValidateHostId(searchParams)
  if (typeof hostIdResult !== 'number') {
    return createValidationError(hostIdResult.message, ROUTE_CONTEXT)
  }
  const hostId = hostIdResult

  // Get and validate query parameter
  const query = searchParams.get('query')
  if (!query || query.trim() === '') {
    return createValidationError(
      'Missing required parameter: query',
      ROUTE_CONTEXT
    )
  }

  // Validate query length
  if (query.length > 100000) {
    return createErrorResponse(
      {
        type: ApiErrorType.ValidationError,
        message: 'Query is too long (maximum 100000 characters)',
      },
      400,
      { ...ROUTE_CONTEXT, hostId }
    )
  }

  // SECURITY: Validate SQL query to prevent injection attacks
  // Only allow SELECT and WITH queries to be explained
  try {
    validateSqlQuery(query)
  } catch (validationError) {
    logError('[GET /api/v1/explain] Security: SQL validation failed', {
      queryPreview: query.substring(0, 100),
      error:
        validationError instanceof Error
          ? validationError.message
          : 'Unknown error',
    })
    return createErrorResponse(
      {
        type: ApiErrorType.ValidationError,
        message:
          validationError instanceof Error
            ? validationError.message
            : 'SQL validation failed',
      },
      400,
      { ...ROUTE_CONTEXT, hostId }
    )
  }

  debug('[GET /api/v1/explain]', { hostId, queryLength: query.length })

  // Wrap query with EXPLAIN
  const explainQuery = `EXPLAIN ${query}`

  // Execute the query
  const result = await fetchData({
    query: explainQuery,
    hostId,
    format: 'JSONEachRow',
  })

  // Handle errors
  if (result.error) {
    logError('[GET /api/v1/explain] Query error:', result.error)

    // Map FetchDataError type to ApiErrorType
    const errorTypeMap: Record<string, ApiErrorType> = {
      table_not_found: ApiErrorType.TableNotFound,
      validation_error: ApiErrorType.ValidationError,
      query_error: ApiErrorType.QueryError,
      network_error: ApiErrorType.NetworkError,
      permission_error: ApiErrorType.PermissionError,
    }

    const apiErrorType =
      errorTypeMap[result.error.type] ?? ApiErrorType.QueryError

    return createErrorResponse(
      {
        type: apiErrorType,
        message: result.error.message,
        details: result.error.details as Record<
          string,
          string | number | boolean | undefined
        >,
      },
      mapErrorTypeToStatusCode(apiErrorType),
      { ...ROUTE_CONTEXT, hostId }
    )
  }

  // Create successful response with no-cache headers
  return createCachedResponse(
    result.data,
    'no-store, no-cache, must-revalidate',
    {
      sql: explainQuery,
      rows: Number(result.metadata.rows || 0),
      duration: Number(result.metadata.duration || 0),
      queryId: String(result.metadata.queryId || ''),
    }
  )
}

/**
 * Validate required search parameters
 */
function validateSearchParams(
  searchParams: URLSearchParams
): { message: string } | null {
  const requiredParams = ['hostId', 'query']

  for (const param of requiredParams) {
    const value = searchParams.get(param)
    if (!value || value.trim() === '') {
      return { message: `Missing required parameter: ${param}` }
    }
  }

  return null
}

'use client'

import { usePathname, useRouter, useSearchParams } from 'next/navigation'
import { useCallback, useMemo } from 'react'

export type ExplorerTab =
  | 'data'
  | 'structure'
  | 'ddl'
  | 'indexes'
  | 'dependencies'

export interface ExplorerState {
  hostId: number
  database: string | null
  table: string | null
  engine: string | null
  tab: ExplorerTab
}

export function useExplorerState(): ExplorerState & {
  setDatabase: (database: string | null) => void
  setTable: (table: string | null, engine?: string | null) => void
  setDatabaseAndTable: (
    database: string,
    table: string,
    engine?: string
  ) => void
  setTab: (tab: ExplorerTab) => void
} {
  const searchParams = useSearchParams()
  const router = useRouter()
  const pathname = usePathname()

  const state = useMemo<ExplorerState>(() => {
    const hostParam = searchParams.get('host')
    const hostId = hostParam !== null ? Number(hostParam) : 0

    return {
      hostId: Number.isNaN(hostId) ? 0 : hostId,
      database: searchParams.get('database'),
      table: searchParams.get('table'),
      engine: searchParams.get('engine'),
      tab: (searchParams.get('tab') as ExplorerTab) || 'data',
    }
  }, [searchParams])

  const updateParams = useCallback(
    (updates: Partial<Omit<ExplorerState, 'hostId'>>) => {
      const params = new URLSearchParams(searchParams.toString())

      if (updates.database !== undefined) {
        if (updates.database === null) {
          params.delete('database')
          params.delete('table') // Clear table when database is cleared
          params.delete('engine')
        } else {
          params.set('database', updates.database)
        }
      }

      if (updates.table !== undefined) {
        if (updates.table === null) {
          params.delete('table')
          params.delete('engine')
        } else {
          params.set('table', updates.table)
        }
      }

      if (updates.engine !== undefined) {
        if (updates.engine === null) {
          params.delete('engine')
        } else {
          params.set('engine', updates.engine)
        }
      }

      if (updates.tab !== undefined) {
        params.set('tab', updates.tab)
      }

      router.push(`${pathname}?${params.toString()}`)
    },
    [searchParams, pathname, router]
  )

  const setDatabase = useCallback(
    (database: string | null) => {
      updateParams({ database, table: null }) // Clear table when changing database
    },
    [updateParams]
  )

  const setTable = useCallback(
    (table: string | null, engine?: string | null) => {
      updateParams({ table, engine: engine ?? null })
    },
    [updateParams]
  )

  const setDatabaseAndTable = useCallback(
    (database: string, table: string, engine?: string) => {
      updateParams({ database, table, engine: engine ?? null, tab: 'data' })
    },
    [updateParams]
  )

  const setTab = useCallback(
    (tab: ExplorerTab) => {
      updateParams({ tab })
    },
    [updateParams]
  )

  return {
    ...state,
    setDatabase,
    setTable,
    setDatabaseAndTable,
    setTab,
  }
}

