'use client'

import { ExternalLink, Loader2 } from 'lucide-react'

import { DatabaseOverview } from './database-overview'
import { ExplorerBreadcrumb } from './explorer-breadcrumb'
import { ExplorerEmptyState } from './explorer-empty-state'
import { useExplorerState } from './hooks/use-explorer-state'
import { DataTab } from './tabs/data-tab'
import { DdlTab } from './tabs/ddl-tab'
import { DependenciesTab } from './tabs/dependencies-tab'
import { IndexesTab } from './tabs/indexes-tab'
import { QueryTab } from './tabs/query-tab'
import { StructureTab } from './tabs/structure-tab'
import Link from 'next/link'
import { useEffect, useRef, useState } from 'react'
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs'
import { useHostId } from '@/lib/swr'
import { cn } from '@/lib/utils'

interface ExplorerContentProps {
  hostName?: string
}

// Track which tabs have been visited for this table to enable pre-loading
function useTabVisitTracker(tableKey: string | null) {
  const [visitedTabs, setVisitedTabs] = useState<Set<string>>(new Set(['data']))
  const prevTableKey = useRef<string | null>(null)

  useEffect(() => {
    if (tableKey !== prevTableKey.current) {
      // Reset visited tabs when table changes
      setVisitedTabs(new Set(['data']))
      prevTableKey.current = tableKey
    }
  }, [tableKey])

  const markVisited = (tab: string) => {
    setVisitedTabs((prev) => new Set([...prev, tab]))
  }

  return { visitedTabs, markVisited }
}

export function ExplorerContent({ hostName }: ExplorerContentProps) {
  const hostId = useHostId()
  const { database, table, tab, setTab } = useExplorerState()
  const [isTabSwitching, setIsTabSwitching] = useState(false)
  const tableKey = database && table ? `${database}.${table}` : null
  const { visitedTabs, markVisited } = useTabVisitTracker(tableKey)

  // Handle tab switching with instant visual feedback
  const handleTabChange = (value: string) => {
    if (value === tab) return

    setIsTabSwitching(true)
    markVisited(value)
    setTab(value as any)

    // Clear switching state after a brief moment
    requestAnimationFrame(() => {
      setIsTabSwitching(false)
    })
  }

  // When query tab is active, show it regardless of database/table selection
  if (tab === 'query') {
    return (
      <div className="flex h-full flex-col gap-4 overflow-y-auto p-4">
        <ExplorerBreadcrumb hostName={hostName} />
        <QueryTab />
      </div>
    )
  }

  if (!database) {
    return <ExplorerEmptyState />
  }

  // Show database-level overview when database selected but no table
  if (!table) {
    return <DatabaseOverview database={database} hostId={hostId} />
  }

  const partInfoUrl = `/part-info?host=${hostId}&database=${encodeURIComponent(database)}&table=${encodeURIComponent(table)}`

  return (
    <div className="flex h-full flex-col gap-4 overflow-y-auto p-4">
      <ExplorerBreadcrumb hostName={hostName} />

      <Tabs id="explorer-tabs" value={tab} onValueChange={handleTabChange}>
        <TabsList>
          <TabsTrigger value="data" className="gap-2">
            Data
            {isTabSwitching && tab === 'data' && (
              <Loader2 className="size-3 animate-spin" />
            )}
          </TabsTrigger>
          <TabsTrigger value="structure" className="gap-2">
            Structure
            {isTabSwitching && tab === 'structure' && (
              <Loader2 className="size-3 animate-spin" />
            )}
          </TabsTrigger>
          <TabsTrigger value="ddl" className="gap-2">
            DDL
            {isTabSwitching && tab === 'ddl' && (
              <Loader2 className="size-3 animate-spin" />
            )}
          </TabsTrigger>
          <TabsTrigger value="indexes" className="gap-2">
            Indexes
            {isTabSwitching && tab === 'indexes' && (
              <Loader2 className="size-3 animate-spin" />
            )}
          </TabsTrigger>
          <TabsTrigger value="dependencies" className="gap-2">
            Dependencies
            {isTabSwitching && tab === 'dependencies' && (
              <Loader2 className="size-3 animate-spin" />
            )}
          </TabsTrigger>
          <Link
            href={partInfoUrl}
            className="inline-flex items-center justify-center gap-1.5 whitespace-nowrap rounded-md px-3 py-1 text-sm font-medium ring-offset-background transition-all focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 text-muted-foreground hover:text-foreground hover:bg-muted"
          >
            Parts
            <ExternalLink className="size-3" />
          </Link>
        </TabsList>

        {/* Data tab: always force-mounted to preserve pagination state */}
        <TabsContent
          value="data"
          className={cn('mt-4', tab !== 'data' && 'hidden flex-none')}
          forceMount
        >
          <DataTab />
        </TabsContent>

        {/* Structure tab: don't force-mount due to complex filter state */}
        <TabsContent value="structure" className="mt-4 flex-none">
          <StructureTab />
        </TabsContent>

        {/* DDL tab: force-mount to keep content cached */}
        <TabsContent
          value="ddl"
          className={cn('mt-4', tab !== 'ddl' && 'hidden flex-none')}
          forceMount
        >
          {visitedTabs.has('ddl') && <DdlTab />}
        </TabsContent>

        {/* Indexes tab: force-mount to keep content cached */}
        <TabsContent
          value="indexes"
          className={cn('mt-4', tab !== 'indexes' && 'hidden flex-none')}
          forceMount
        >
          {visitedTabs.has('indexes') && <IndexesTab />}
        </TabsContent>

        {/* Dependencies tab: force-mount to keep content cached */}
        <TabsContent
          value="dependencies"
          className={cn('mt-4', tab !== 'dependencies' && 'hidden flex-none')}
          forceMount
        >
          {visitedTabs.has('dependencies') && <DependenciesTab />}
        </TabsContent>

      </Tabs>
    </div>
  )
}

'use client'

import { usePathname, useRouter, useSearchParams } from 'next/navigation'
import { useCallback, useMemo } from 'react'

export type ExplorerTab =
  | 'data'
  | 'structure'
  | 'ddl'
  | 'indexes'
  | 'dependencies'
  | 'query'

export interface ExplorerState {
  hostId: number
  database: string | null
  table: string | null
  engine: string | null
  tab: ExplorerTab
  customQuery: string | null
}

export function useExplorerState(): ExplorerState & {
  setDatabase: (database: string | null) => void
  setTable: (table: string | null, engine?: string | null) => void
  setDatabaseAndTable: (
    database: string,
    table: string,
    engine?: string
  ) => void
  setTab: (tab: ExplorerTab) => void
  setCustomQuery: (sql: string | null) => void
} {
  const searchParams = useSearchParams()
  const router = useRouter()
  const pathname = usePathname()

  const state = useMemo<ExplorerState>(() => {
    const hostParam = searchParams.get('host')
    const hostId = hostParam !== null ? Number(hostParam) : 0

    const q = searchParams.get('q')
    let customQuery: string | null = null
    if (q) {
      try {
        customQuery = decodeURIComponent(atob(q))
      } catch {
        customQuery = null
      }
    }

    return {
      hostId: Number.isNaN(hostId) ? 0 : hostId,
      database: searchParams.get('database'),
      table: searchParams.get('table'),
      engine: searchParams.get('engine'),
      tab: (searchParams.get('tab') as ExplorerTab) || 'data',
      customQuery,
    }
  }, [searchParams])

  const updateParams = useCallback(
    (updates: Partial<Omit<ExplorerState, 'hostId'>>) => {
      const params = new URLSearchParams(searchParams.toString())

      if (updates.database !== undefined) {
        if (updates.database === null) {
          params.delete('database')
          params.delete('table') // Clear table when database is cleared
          params.delete('engine')
        } else {
          params.set('database', updates.database)
        }
      }

      if (updates.table !== undefined) {
        if (updates.table === null) {
          params.delete('table')
          params.delete('engine')
        } else {
          params.set('table', updates.table)
        }
      }

      if (updates.engine !== undefined) {
        if (updates.engine === null) {
          params.delete('engine')
        } else {
          params.set('engine', updates.engine)
        }
      }

      if (updates.tab !== undefined) {
        params.set('tab', updates.tab)
      }

      router.push(`${pathname}?${params.toString()}`)
    },
    [searchParams, pathname, router]
  )

  const setDatabase = useCallback(
    (database: string | null) => {
      updateParams({ database, table: null }) // Clear table when changing database
    },
    [updateParams]
  )

  const setTable = useCallback(
    (table: string | null, engine?: string | null) => {
      updateParams({ table, engine: engine ?? null })
    },
    [updateParams]
  )

  const setDatabaseAndTable = useCallback(
    (database: string, table: string, engine?: string) => {
      updateParams({ database, table, engine: engine ?? null, tab: 'data' })
    },
    [updateParams]
  )

  const setTab = useCallback(
    (tab: ExplorerTab) => {
      updateParams({ tab })
    },
    [updateParams]
  )

  const setCustomQuery = useCallback(
    (sql: string | null) => {
      const params = new URLSearchParams(searchParams.toString())
      if (sql === null) {
        params.delete('q')
      } else {
        params.set('q', btoa(encodeURIComponent(sql)))
      }
      router.push(`${pathname}?${params.toString()}`)
    },
    [searchParams, pathname, router]
  )

  return {
    ...state,
    setDatabase,
    setTable,
    setDatabaseAndTable,
    setTab,
    setCustomQuery,
  }
}

/**
 * Explorer query endpoint
 * GET /api/v1/explorer/query?hostId=0&sql=SELECT...&format=JSONEachRow&timezone=UTC
 *
 * Executes custom SQL queries from the explorer page.
 * Only SELECT queries are allowed; all queries run in readonly mode.
 */

import type { NextRequest } from 'next/server'
import type { ApiResponse } from '@/lib/api/types'

import {
  createErrorResponse as createApiErrorResponse,
  getHostIdFromParams,
  type RouteContext,
} from '@/lib/api/error-handler'
import { ApiErrorType } from '@/lib/api/types'
import { validateSqlQuery } from '@/lib/api/shared/validators/sql'
import { fetchData } from '@/lib/clickhouse'
import { debug, error } from '@/lib/logger'

export const dynamic = 'force-dynamic'

const ROUTE_CONTEXT_BASE = { route: '/api/v1/explorer/query' }

/** Maximum allowed query length in characters */
const MAX_QUERY_LENGTH = 100_000

/**
 * Handle GET requests for custom SQL query execution
 */
export async function GET(request: NextRequest): Promise<Response> {
  const { searchParams } = new URL(request.url)
  const routeContext: RouteContext = {
    ...ROUTE_CONTEXT_BASE,
    method: 'GET',
  }

  // Extract and validate hostId
  const hostId = getHostIdFromParams(searchParams, routeContext)

  // Extract query parameters
  const sql = searchParams.get('sql')
  const format = searchParams.get('format') || 'JSONEachRow'
  const timezone = searchParams.get('timezone')

  debug(`[GET /api/v1/explorer/query]`, { hostId, format, timezone })

  // Validate sql parameter is present
  if (!sql) {
    return createApiErrorResponse(
      {
        type: ApiErrorType.ValidationError,
        message: 'Missing required parameter: sql',
        details: {
          sql: 'missing',
        },
      },
      400,
      routeContext
    )
  }

  // Validate query length
  if (sql.length > MAX_QUERY_LENGTH) {
    return createApiErrorResponse(
      {
        type: ApiErrorType.ValidationError,
        message: `SQL query exceeds maximum length of ${MAX_QUERY_LENGTH} characters`,
        details: {
          length: sql.length,
          maxLength: MAX_QUERY_LENGTH,
        },
      },
      400,
      routeContext
    )
  }

  // Validate SQL query for safety (SELECT-only, no dangerous keywords)
  try {
    validateSqlQuery(sql)
  } catch (validationError) {
    return createApiErrorResponse(
      {
        type: ApiErrorType.ValidationError,
        message:
          validationError instanceof Error
            ? validationError.message
            : 'Invalid SQL query',
        details: {
          sql,
        },
      },
      400,
      routeContext
    )
  }

  // Validate format parameter
  const allowedFormats = ['JSONEachRow', 'JSON', 'CSV', 'TSV']
  if (!allowedFormats.includes(format)) {
    return createApiErrorResponse(
      {
        type: ApiErrorType.ValidationError,
        message: `Invalid format parameter. Allowed formats: ${allowedFormats.join(', ')}`,
        details: {
          format,
        },
      },
      400,
      routeContext
    )
  }

  debug(`[GET /api/v1/explorer/query] Executing query:`, {
    sql,
    format,
    timezone,
  })

  // Build ClickHouse settings with readonly mode
  const clickhouse_settings: Record<string, string | number> = {
    readonly: 1,
  }

  if (timezone) {
    clickhouse_settings.session_timezone = timezone
  }

  // Execute the query
  const result = await fetchData({
    query: sql,
    hostId,
    format,
    clickhouse_settings,
  })

  // Check if there was an error
  if (result.error) {
    error(`[GET /api/v1/explorer/query] Query error:`, result.error)
    return createApiErrorResponse(
      {
        type: result.error.type as ApiErrorType,
        message: result.error.message,
        details: result.error.details as Record<
          string,
          string | number | boolean | undefined
        >,
      },
      mapErrorTypeToStatusCode(result.error.type as ApiErrorType),
      { ...routeContext, hostId }
    )
  }

  // Create successful response
  return createSuccessResponse(result.data, result.metadata)
}

/**
 * Map error type to HTTP status code
 */
function mapErrorTypeToStatusCode(errorType: ApiErrorType): number {
  const statusMap: Record<ApiErrorType, number> = {
    [ApiErrorType.ValidationError]: 400,
    [ApiErrorType.PermissionError]: 403,
    [ApiErrorType.TableNotFound]: 404,
    [ApiErrorType.NetworkError]: 503,
    [ApiErrorType.QueryError]: 500,
  }

  return statusMap[errorType] || 500
}

/**
 * Create a success response
 */
function createSuccessResponse<T>(
  data: T,
  metadata: Record<string, string | number>
): Response {
  const response: ApiResponse<T> = {
    success: true,
    data,
    metadata: {
      queryId: String(metadata.queryId || ''),
      duration: Number(metadata.duration || 0),
      rows: Number(metadata.rows || 0),
      host: String(metadata.host || ''),
    },
  }

  return Response.json(response, {
    status: 200,
    headers: {
      'Content-Type': 'application/json',
      'Cache-Control': 'private, max-age=0',
    },
  })
}

