          spellCheck={false}
        />
        {validationError && (
          <p className="text-sm text-destructive">{validationError}</p>
        )}
        <div className="flex items-center gap-2">
          <Button
            onClick={handleRun}
            disabled={isLoading || !editorValue.trim()}
            size="sm"
          >
            {isLoading ? (
              <Loader2 className="mr-1.5 size-3.5 animate-spin" />
            ) : (
              <Play className="mr-1.5 size-3.5" />
            )}
            Run Query
          </Button>
        </div>
      </div>

      {/* Error Display */}
      {error && (
        <Alert
          variant="destructive"
          className={cn(
            error instanceof QueryTabError &&
              error.type === 'permission_error' &&
              'border-amber-500/50 bg-amber-500/10'
          )}
        >
          {error instanceof QueryTabError &&
          error.type === 'permission_error' ? (
            <ShieldAlert className="size-4" />
          ) : (
            <AlertCircle className="size-4" />
          )}
          <AlertTitle>
            {error instanceof QueryTabError &&
            error.type === 'permission_error'
              ? 'Permission Denied'
              : 'Query Error'}
          </AlertTitle>
          <AlertDescription>
            <p className="text-sm">{error.message}</p>
          </AlertDescription>
        </Alert>
      )}

      {/* Metadata Bar */}
      {metadata && !error && (
        <MetadataBar metadata={metadata} isValidating={isValidating} />
      )}

      {/* Results Table */}
      {rows.length > 0 && (
        <div
          className={cn(
            'overflow-x-auto rounded-md border transition-opacity',
            isValidating && 'opacity-60'
          )}
        >
          <Table
            style={{
              minWidth: table.getCenterTotalSize(),
              width: '100%',
            }}
          >
            <TableHeader className="bg-muted/50">
              {table.getHeaderGroups().map((headerGroup) => (
                <TableRow key={headerGroup.id}>
                  {headerGroup.headers.map((header) => (
                    <TableHead
                      key={header.id}
                      className="relative select-none"
                      style={{
                        minWidth: header.getSize(),
                      }}
                    >
                      {header.isPlaceholder
                        ? null
                        : flexRender(
                            header.column.columnDef.header,
                            header.getContext()
                          )}
                      {/* Column resize handle */}
                      <div
                        role="presentation"
                        onDoubleClick={() => header.column.resetSize()}
                        onMouseDown={header.getResizeHandler()}
                        onTouchStart={header.getResizeHandler()}
                        className={cn(
                          'absolute right-0 top-0 h-full w-1 cursor-col-resize select-none touch-none',
                          'bg-transparent hover:bg-primary/50',
                          header.column.getIsResizing() && 'bg-primary'
                        )}
                      />
                    </TableHead>
                  ))}
                </TableRow>
              ))}
            </TableHeader>
            <TableBody>
              {table.getRowModel().rows.map((row) => (
                <TableRow key={row.id} className="hover:bg-muted/50">
                  {row.getVisibleCells().map((cell) => (
                    <TableCell
                      key={cell.id}
                      style={{
                        minWidth: cell.column.getSize(),
                      }}
                    >
                      {flexRender(
                        cell.column.columnDef.cell,
                        cell.getContext()
                      )}
                    </TableCell>
                  ))}
                </TableRow>
              ))}
            </TableBody>
          </Table>
        </div>
      )}

      {/* Empty result */}
      {executedQuery && !isLoading && !error && rows.length === 0 && (
        <div className="p-4 text-sm text-muted-foreground">
          Query returned no results.
        </div>
      )}
    </div>
  )
}

function MetadataBar({
  metadata,
  isValidating,
}: {
  metadata: ApiResponseMetadata
  isValidating: boolean
}) {
  return (
    <div className="flex items-center gap-2 flex-wrap">
      <Badge variant="secondary" className="gap-1 font-mono text-xs">
        <RowsIcon className="size-3" />
        {metadata.rows} row{metadata.rows !== 1 ? 's' : ''}
      </Badge>
      <Badge variant="secondary" className="gap-1 font-mono text-xs">
        <Clock className="size-3" />
        {metadata.duration}ms
      </Badge>
      {isValidating && (
        <Loader2 className="size-3 animate-spin text-muted-foreground" />
      )}
    </div>
  )
}

